7440	void diff_add_if_missing(struct repository *r,
7441				 struct oid_array *to_fetch,
7442				 const struct diff_filespec *filespec)
7443	{
7444		if (filespec && filespec->oid_valid &&
7445		    !S_ISGITLINK(filespec->mode) &&
7446		    odb_read_object_info_extended(r->objects, &filespec->oid, NULL,
7447						  OBJECT_INFO_FOR_PREFETCH))
7448			oid_array_append(to_fetch, &filespec->oid);
7449	}
7450	
7451	void diff_queued_diff_prefetch(void *repository)
7452	{
7453		struct repository *repo = repository;
7454		int i;
7455		struct diff_queue_struct *q = &diff_queued_diff;
7456		struct oid_array to_fetch = OID_ARRAY_INIT;
7457	
7458		for (i = 0; i < q->nr; i++) {
7459			struct diff_filepair *p = q->queue[i];
7460	
7461			if (!p)
7462				continue;
7463	
7464			diff_add_if_missing(repo, &to_fetch, p->one);
7465			diff_add_if_missing(repo, &to_fetch, p->two);
7466		}
7467	
7468		/*
7469		 * NEEDSWORK: Consider deduplicating the OIDs sent.
7470		 */
7471		promisor_remote_get_direct(repo, to_fetch.oid, to_fetch.nr);
7472	
7473		oid_array_clear(&to_fetch);
7474	}
7475	
7476	void init_diffstat_widths(struct diff_options *options)
7477	{
7478		options->stat_width = -1;        /* use full terminal width */
7479		options->stat_name_width = -1;   /* respect diff.statNameWidth config */
7480		options->stat_graph_width = -1;  /* respect diff.statGraphWidth config */
7481	}
7482	
7483	void diffcore_std(struct diff_options *options)
7484	{
7485		int output_formats_to_prefetch = DIFF_FORMAT_DIFFSTAT |
7486			DIFF_FORMAT_NUMSTAT |
7487			DIFF_FORMAT_PATCH |
7488			DIFF_FORMAT_SHORTSTAT |
7489			DIFF_FORMAT_DIRSTAT;
7490	
7491		/*
7492		 * Check if the user requested a blob-data-requiring diff output and/or
7493		 * break-rewrite detection (which requires blob data). If yes, prefetch
7494		 * the diff pairs.
7495		 *
7496		 * If no prefetching occurs, diffcore_rename() will prefetch if it
7497		 * decides that it needs inexact rename detection.
7498		 */
7499		if (repo_has_promisor_remote(options->repo) &&
7500		    (options->output_format & output_formats_to_prefetch ||
7501		     options->pickaxe_opts & DIFF_PICKAXE_KINDS_MASK))
7502			diff_queued_diff_prefetch(options->repo);
7503	
7504		/* NOTE please keep the following in sync with diff_tree_combined() */
7505		if (options->skip_stat_unmatch)
7506			diffcore_skip_stat_unmatch(options);
7507		if (!options->found_follow) {
7508			/* See try_to_follow_renames() in tree-diff.c */
7509			if (options->break_opt != -1)
7510				diffcore_break(options->repo,
7511					       options->break_opt);
7512			if (options->detect_rename)
7513				diffcore_rename(options);
7514			if (options->break_opt != -1)
7515				diffcore_merge_broken();
