239	static void merge_broken(struct diff_filepair *p,
240				 struct diff_filepair *pp,
241				 struct diff_queue_struct *outq)
242	{
243		/* p and pp are broken pairs we want to merge */
244		struct diff_filepair *c = p, *d = pp, *dp;
245		if (DIFF_FILE_VALID(p->one)) {
246			/* this must be a delete half */
247			d = p; c = pp;
248		}
249		/* Sanity check */
250		if (!DIFF_FILE_VALID(d->one))
251			die("internal error in merge #1");
252		if (DIFF_FILE_VALID(d->two))
253			die("internal error in merge #2");
254		if (DIFF_FILE_VALID(c->one))
255			die("internal error in merge #3");
256		if (!DIFF_FILE_VALID(c->two))
257			die("internal error in merge #4");
258	
259		dp = diff_queue(outq, d->one, c->two);
260		dp->score = p->score;
261		/*
262		 * We will be one extra user of the same src side of the
263		 * broken pair, if it was used as the rename source for other
264		 * paths elsewhere.  Increment to mark that the path stays
265		 * in the resulting tree.
266		 */
267		d->one->rename_used++;
268		free_filespec(d->two);
269		free_filespec(c->one);
270		free(d);
271		free(c);
272	}
273	
274	void diffcore_merge_broken(void)
275	{
276		struct diff_queue_struct *q = &diff_queued_diff;
277		struct diff_queue_struct outq = DIFF_QUEUE_INIT;
278		int i, j;
279	
280		for (i = 0; i < q->nr; i++) {
281			struct diff_filepair *p = q->queue[i];
282			if (!p)
283				/* we already merged this with its peer */
284				continue;
285			else if (p->broken_pair &&
286				 !strcmp(p->one->path, p->two->path)) {
287				/* If the peer also survived rename/copy, then
288				 * we merge them back together.
289				 */
290				for (j = i + 1; j < q->nr; j++) {
291					struct diff_filepair *pp = q->queue[j];
292					if (pp->broken_pair &&
293					    !strcmp(pp->one->path, pp->two->path) &&
294					    !strcmp(p->one->path, pp->two->path)) {
295						/* Peer survived.  Merge them */
296						merge_broken(p, pp, &outq);
297						q->queue[j] = NULL;
298						goto next;
299					}
300				}
301				/* The peer did not survive, so we keep
302				 * it in the output.
303				 */
304				diff_q(&outq, p);
305			}
306			else
307				diff_q(&outq, p);
308	next:;
309		}
310		free(q->queue);
311		*q = outq;
312	
313		return;
314	}
